    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "market": "ETH-EUR",
        //         "offerType": "Sell",
        //         "id": "93d3657b-d616-11e9-9248-0242ac110005",
        //         "currentAmount": "0.04",
        //         "lockedAmount": "0.04",
        //         "rate": "280",
        //         "startAmount": "0.04",
        //         "time": "1568372806924",
        //         "postOnly": false,
        //         "hidden": false,
        //         "mode": "limit",
        //         "receivedAmount": "0.0",
        //         "firstBalanceId": "5b816c3e-437c-4e43-9bef-47814ae7ebfc",
        //         "secondBalanceId": "ab43023b-4079-414c-b340-056e3430a3af"
        //     }
        //
        // cancelOrder
        //
        //    {
        //        status: "Ok",
        //        errors: []
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "market");
        Object symbol = this.safeSymbol(marketId, market, "-");
        Object timestamp = this.safeInteger(order, "time");
        Object amount = this.safeString(order, "startAmount");
        Object remaining = this.safeString(order, "currentAmount");
        Object postOnly = this.safeValue(order, "postOnly");
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", ZondaCore.this.safeString(order, "id") );
            put( "clientOrderId", null );
            put( "info", order );
            put( "timestamp", timestamp );
            put( "datetime", ZondaCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", null );
            put( "symbol", symbol );
            put( "type", ZondaCore.this.safeString(order, "mode") );
            put( "timeInForce", null );
            put( "postOnly", postOnly );
            put( "side", ZondaCore.this.safeStringLower(order, "offerType") );
            put( "price", ZondaCore.this.safeString(order, "rate") );
            put( "triggerPrice", null );
            put( "amount", amount );
            put( "cost", null );
            put( "filled", null );
            put( "remaining", remaining );
            put( "average", null );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

    /**
     * @method
     * @name zonda#fetchMyTrades
     * @see https://docs.zondacrypto.exchange/reference/transactions-history
     * @description fetch all trades made by the user
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(symbol))
            {
                Object markets = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.marketId(symbol)));
                symbol = this.symbol(symbol);
                Helpers.addElementToObject(request, "markets", markets);
            }
            Object query = new java.util.HashMap<String, Object>() {{
                put( "query", ZondaCore.this.json(ZondaCore.this.extend(request, parameters)) );
            }};
            Object response = (this.v1_01PrivateGetTradingHistoryTransactions(query)).join();
            //
            //     {
            //         "status": "Ok",
            //         "totalRows": "67",
            //         "items": [
            //             {
            //                 "id": "b54659a0-51b5-42a0-80eb-2ac5357ccee2",
            //                 "market": "BTC-EUR",
            //                 "time": "1541697096247",
            //                 "amount": "0.00003",
            //                 "rate": "4341.44",
            //                 "initializedBy": "Sell",
            //                 "wasTaker": false,
            //                 "userAction": "Buy",
            //                 "offerId": "bd19804a-6f89-4a69-adb8-eb078900d006",
            //                 "commissionValue": null
            //             },
            //         ]
            //     }
            //
            Object items = this.safeValue(response, "items");
            Object result = this.parseTrades(items, null, since, limit);
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                return result;
            }
            return this.filterBySymbol(result, symbol);
        });

    }

    public Object parseBalance(Object response)
    {
        Object balances = this.safeValue(response, "balances");
        if (Helpers.isTrue(Helpers.isEqual(balances, null)))
        {
            throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " empty balance response "), this.json(response))) ;
        }
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balance = Helpers.GetValue(balances, i);
            Object currencyId = this.safeString(balance, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "used", this.safeString(balance, "lockedFunds"));
            Helpers.addElementToObject(account, "free", this.safeString(balance, "availableFunds"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

